import pytest
import requests

def test_create_patient_multiple_missing_mandatory_fields_returns_422(
    clinician_auth_header, base_url, unique_identifier
):
    cases = [
        {
            "label": "missing name+birthDate",
            "payload": {
                "resourceType": "Patient",
                "identifier": [{"system": "urn:test", "value": unique_identifier("DT-A")}],
                "gender": "male"
            }
        },
        {
            "label": "missing gender+birthDate",
            "payload": {
                "resourceType": "Patient",
                "identifier": [{"system": "urn:test", "value": unique_identifier("DT-B")}],
                "name": [{"family": "Delta", "given": ["Test"]}]
            }
        },
        {
            "label": "missing name+gender+birthDate",
            "payload": {
                "resourceType": "Patient",
                "identifier": [{"system": "urn:test", "value": unique_identifier("DT-C")}]
            }
        }
    ]
    for case in cases:
        resp = requests.post(
            f"{base_url}/Patient",
            json=case["payload"],
            headers=clinician_auth_header
        )
        assert resp.status_code == 422, (
            f"Case '{case['label']}': Expected 422, got {resp.status_code}: {resp.text}"
        )
